class Singleton
{
public:
    static Singleton* Get()
    {
        if (instance_ == nullptr)
        {
            std::lock_guard<std::mutex> lock(mutex_);

            if (instance_ == nullptr)
            {
                instance_ = new Singleton();
            }
        }

        return instance_;
    }

private:
    Singleton() = default;

    static Singleton* instance_;
    static std::mutex mutex_;
};
